// 在 Controller 或 Service 裡
public class OrderController : ControllerBase
{
    private readonly IBackgroundJobClient _jobClient;

    public OrderController(IBackgroundJobClient jobClient)
    {
        _jobClient = jobClient;
    }

    [HttpPost]
    public IActionResult CreateOrder(Order order)
    {
        // 立即入隊、排隊發信
        _jobClient.Enqueue<EmailService>(x => 
            x.SendEmail(order.Email, "訂單確認", "感謝你的訂單...")
        );

        // 也可以延遲執行
        _jobClient.Schedule<EmailService>(x =>
            x.SendEmail(order.Email, "提醒", "再不領貨就退回了"),
            TimeSpan.FromDays(7) // 7 天後
        );

        return Ok();
    }
}
```

**實戰應用**：發送郵件、生成報表、定期備份、聲譽檢查。

